const fs = require('fs');
const path = require('path');
const matter = require('gray-matter');
const repo = $env.EMPIRE_REPO_PATH;
const paths = ($input.item.json.stdout || '').split('\n').filter(Boolean);
const now = Date.now();
const stale = [];
for (const rel of paths) {
  const full = path.resolve(repo, rel);
  let raw; try { raw = fs.readFileSync(full, 'utf8'); } catch { continue; }
  const fm = matter(raw).data || {};
  const lr = fm.last_reviewed || fm.lastReviewed;
  const lrDate = lr ? new Date(lr).getTime() : null;
  const ageDays = lrDate ? Math.floor((now - lrDate) / 86400000) : null;
  if (ageDays === null || ageDays > 180) {
    stale.push({ rel, title: fm.title || rel, ageDays });
  }
}
if (stale.length === 0) return [];
const lines = stale.slice(0, 10).map(s => `• ${s.title} (${s.ageDays === null ? 'undated' : s.ageDays + 'd old'})`).join('\n');
return [{ json: {
  priority: 'P1',
  source: 'runbook-staleness',
  message: `${stale.length} runbook${stale.length>1?'s':''} stale or undated:\n${lines}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/maintain/runbooks'
}}];
